using System;
using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

class PropertyEditor : UITypeEditor
{
    public override object EditValue(ITypeDescriptorContext context, IServiceProvider provider, object value)
    {
        var editorService = (IWindowsFormsEditorService)provider.GetService(typeof(IWindowsFormsEditorService));
        if (editorService is null)
            return value;

        Control dropDown = CreateDropDown(value);

        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
        // when passed null instead of silently returning.
        if (dropDown is not null)
        {
            editorService.DropDownControl(dropDown);
        }

        return dropDown?.Tag ?? value;
    }

    private Control CreateDropDown(object value)
    {
        if (value is null)
            return null;

        var listBox = new ListBox();
        listBox.Tag = value;
        return listBox;
    }
}

